function CourseList({ courses, del }) {
  return (
    <ul className="space-y-2">
      {courses.map((c, i) => (
        <li
          key={i}
          className="flex justify-between items-center border p-2 rounded"
        >
          <span>{c}</span>
          <button
            onClick={() => del(i)}
            className="text-red-500 hover:text-red-700"
          >
            Xóa
          </button>
        </li>
      ))}
    </ul>
  );
}

export default CourseList;
